targets.rawSql:
SELECT time, AVG(battery_soc) AS "SOC %"
FROM solar_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
GROUP BY time ORDER BY time DESC LIMIT 1

SELECT time, temp_c AS "Temp °C"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1

SELECT time, cloud_cover AS "Cloud %"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1

SELECT time, solar_rad AS "W/m²"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1

SELECT time, wind_speed AS "km/h"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1

SELECT time, humidity AS "Hum %"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1

SELECT time, uv_index AS "UV"
FROM weather_readings WHERE $__timeFilter(time) AND site_name ILIKE ${site:singlequote}
ORDER BY time DESC LIMIT 1
